CREATE OR REPLACE FUNCTION OFSERM.ABL_BANKING_LC_EXPOSURE_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_BANKING_EXPOSURES(N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_INSTRUMENT_SKEY,N_ISSUE_SKEY,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,N_REPAYMENT_TYPE_SKEY,F_INTERNAL_CUST_IND,F_UNCOND_CANCELLED_EXP_IND,N_COVERED_RWA_UL,N_CURR_12M_ECL,N_EL_AMOUNT,N_EXPOSURE_AMOUNT,N_EXP_COVERED_AMT,N_EXP_UNCOVERED_AMT,N_GROUP_ASSET_SIZE,N_LOSS_ALLOWANCE_LIFE_ECL,N_MORTGAGE_LENDING_VALUE,N_ORIGINAL_MATURITY,N_INSTR_OTH_VALUATION_ADJ_AMT,N_PRE_MITIGATION_RWA_EL,N_RESIDUAL_MATURITY,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,N_RWA_EL_AMT,N_RWA_UL_AMT,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,N_UNCOVERED_RWA_UL,N_UNDRAWN_AMOUNT,N_INSTR_VALUATION_ADJ_AMOUNT,V_APPROACH_TYPE,V_EXP_RCY_CODE,N_ENTITY_SKEY,N_REG_CAP_ACCT_PURPOSE_SKEY,F_CASH_POOL_DAILY_TRANSFER,F_CASH_POOL_LEGAL_ENFORCEABLE,F_CREDIT_IMPAIRMENT_FLAG,F_FINANCIAL_ASSET_IFRS9_FLAG,F_PREF_TREATMENT_FLAG,F_RW_BY_DISCRETION,N_CCF_OWN_ESTIMATE,N_EFF_MATURITY,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_PROVISION_AMOUNT,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_UNDERLYING_TYPE_SKEY,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,N_STD_SENIORITY_SKEY,N_SEC_POOL_SKEY,D_EXPOSURE_END_DATE,D_EXPOSURE_START_DATE,F_EXP_DEFAULTED_FLAG,F_AUTO_CANCELLATION_FLAG,F_BUYER_SELLER_IND,F_ELIGIBLE_PROTECTION_IND,F_EXP_FUND_CCY_SAME_IND,F_EXP_HELD_AT_FAIR_VALUE,F_GUAR_BY_SOVERIGN_IND,F_NETTABILITY_FLAG,F_PAST_DUE_FLAG,F_REG_CAP_INVST_IND,F_EXP_REV_FLAG,F_SECURED_IND,F_SECURITIZED_FLAG,F_SENIOR_CLAIM_FLAG,N_DELQ_DAYS,N_EXP_SENIORITY,N_LOAD_RUN_ID,N_REMARGIN_FREQUENCY,V_PRODUCT_BOOK_CODE,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),to_char(DIM_REPAYMENT_TYPE.N_REPAYMENT_TYPE_SKEY),CASE  WHEN FCT_ENTITY_INFO_CUST.V_PARTY_ID IS NOT NULL AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ('FLCS', 'PRCS','FAGR','PRAGR')  THEN  'Y' ELSE 'N'   END,COALESCE(STG_LC_CONTRACTS.F_UNCOND_CANCELLED_EXP_IND,'N'),0,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*(CASE WHEN STG_LC_CONTRACTS.N_EOP_BAL > 0 THEN STG_LC_CONTRACTS.N_EOP_BAL ELSE 0 END),0,0,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*STG_LC_CONTRACTS.N_MORTGAGE_LENDING_VALUE,DAYS_BETWEEN(STG_LC_CONTRACTS.D_START_DATE,STG_LC_CONTRACTS.D_MATURITY_DATE,STG_LC_CONTRACTS.V_DAY_COUNT_IND),FSI_INSTR_VALUATION_DETAILS.N_OTHER_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,0,DAYS_BETWEEN(STG_LC_CONTRACTS.FIC_MIS_DATE,STG_LC_CONTRACTS.D_MATURITY_DATE,STG_LC_CONTRACTS.V_DAY_COUNT_IND),CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY ELSE NULL END,'870',0,0,FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*STG_LC_CONTRACTS.N_UNDRAWN_AMOUNT,FSI_INSTR_VALUATION_DETAILS.N_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE ELSE NULL END,RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FSI_ACCOUNT_PURPOSE_RECLASS.N_REG_CAP_ACCT_PURPOSE_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,FSI_ACCT_MODELING_INFO.F_PREF_TREATMENT_FLAG,FSI_ACCT_MODELING_INFO.F_RW_BY_DISCRETION,to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE),to_char(FSI_ACCT_MODELING_INFO.N_EFF_MATURITY),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_PROVISION_AMOUNT),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_UNDERLYING_TYPE_SKEY),to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(FSI_SENIORITY_RECLASSIFICATION.N_STD_SENIORITY_SKEY),to_char(SEC_POOL_MASTER.N_SEC_POOL_SKEY),STG_LC_CONTRACTS.D_MATURITY_DATE,STG_LC_CONTRACTS.D_START_DATE,STG_LC_CONTRACTS.F_ACCT_DEFAULTED_FLAG,STG_LC_CONTRACTS.F_AUTO_CANCELLATION_FLAG,STG_LC_CONTRACTS.F_BUYER_SELLER_IND,STG_LC_CONTRACTS.F_ELIGIBLE_PROTECTION_IND,STG_LC_CONTRACTS.F_EXP_FUND_CCY_SAME_IND,STG_LC_CONTRACTS.F_EXP_HELD_AT_FAIR_VALUE,STG_LC_CONTRACTS.F_GUAR_BY_SOVERIGN_IND,STG_LC_CONTRACTS.F_NETTABILITY_FLAG,STG_LC_CONTRACTS.F_PAST_DUE_FLAG,STG_LC_CONTRACTS.F_REG_CAP_INVST_IND,STG_LC_CONTRACTS.F_REVOLVE_IND,STG_LC_CONTRACTS.F_SECURED_IND,STG_LC_CONTRACTS.F_SECURITIZED_FLAG,STG_LC_CONTRACTS.F_SENIOR_CLAIM_FLAG,to_char(STG_LC_CONTRACTS.N_DELINQUENT_DAYS),to_char(STG_LC_CONTRACTS.N_EXP_SENIORITY),to_char(STG_LC_CONTRACTS.N_LOAD_RUN_ID),to_char(STG_LC_CONTRACTS.N_REMARGIN_FREQUENCY),STG_LC_CONTRACTS.V_BOOK_TYPE,STG_LC_CONTRACTS.V_CCY_CODE FROM STG_LC_CONTRACTS INNER JOIN dim_dates ON STG_LC_CONTRACTS.fic_mis_date = dim_dates.d_calendar_date INNER JOIN DIM_RUN ON DIM_RUN.n_run_skey = '870' /*LEFT JOIN DIM_PRODUCT ON STG_LC_CONTRACTS.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE*/ INNER JOIN DIM_EXPOSURE ON STG_LC_CONTRACTS.V_CONTRACT_CODE = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.d_record_start_date AND DIM_EXPOSURE.d_record_end_date LEFT OUTER JOIN DIM_PARTY ON STG_LC_CONTRACTS.v_cust_ref_code = DIM_PARTY.v_party_id AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.d_record_start_date AND DIM_PARTY.d_record_end_date INNER JOIN DIM_PARTY_TYPE ON DIM_PARTY.V_PARTY_TYPE = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.d_record_start_date AND DIM_PARTY_TYPE.d_record_end_date LEFT OUTER JOIN DIM_PRODUCT ON STG_LC_CONTRACTS.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.d_record_start_date AND DIM_PRODUCT.d_record_end_date LEFT OUTER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT OUTER JOIN DIM_LOB ON STG_LC_CONTRACTS.V_LOB_CODE = DIM_LOB.V_LOB_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOB.d_record_start_date AND DIM_LOB.d_record_end_date LEFT OUTER JOIN DIM_GEOGRAPHY ON coalesce(DIM_PARTY.V_BRANCH_CODE, 'MSG') = DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GEOGRAPHY.d_record_start_date AND DIM_GEOGRAPHY.d_record_end_date LEFT OUTER JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = coalesce(DIM_PARTY.V_INDUSTRY_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INDUSTRY.d_record_start_date AND DIM_INDUSTRY.d_record_end_date LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.V_GAAP_CODE = STG_LC_CONTRACTS.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT OUTER JOIN SEC_POOL_MASTER ON SEC_POOL_MASTER.V_SEC_POOL_ID = STG_LC_CONTRACTS.V_SEC_POOL_ID AND to_date('20260331','YYYYMMDD') BETWEEN SEC_POOL_MASTER.d_record_start_date AND SEC_POOL_MASTER.d_record_end_date LEFT OUTER JOIN DIM_NETTING_AGREEMENT ON DIM_NETTING_AGREEMENT.V_NETTING_AGREEMENT_CODE = STG_LC_CONTRACTS.V_NETTING_AGREEMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_NETTING_AGREEMENT.D_RECORD_START_DATE AND DIM_NETTING_AGREEMENT.D_RECORD_END_DATE INNER JOIN FCT_ENTITY_INFO ON STG_LC_CONTRACTS.v_lv_code = FCT_ENTITY_INFO.v_entity_code INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.n_basel_cap_consl_appr_skey = FCT_ENTITY_INFO.n_basel_cap_consl_appr_skey LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN DIM_ISSUE ON STG_LC_CONTRACTS.V_CONTRACT_CODE = DIM_ISSUE.v_issue_code AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ISSUE.d_record_start_date AND DIM_ISSUE.d_record_end_date LEFT OUTER JOIN FSI_CAP_PARTY_FINANCIALS ON FSI_CAP_PARTY_FINANCIALS.N_RUN_SKEY = '870' AND FSI_CAP_PARTY_FINANCIALS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_PARTY_FINANCIALS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY LEFT OUTER JOIN ( RUN_EXE_PARAMETERS INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE AND RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' ) ON RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' LEFT OUTER JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT OUTER JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOCATION.D_RECORD_START_DATE AND DIM_LOCATION.D_RECORD_END_DATE LEFT OUTER JOIN DIM_ACCOUNT_PURPOSE ON DIM_ACCOUNT_PURPOSE.V_ACCOUNT_PURPOSE_CODE = STG_LC_CONTRACTS.V_CONTRACT_PURPOSE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ACCOUNT_PURPOSE.D_RECORD_START_DATE AND DIM_ACCOUNT_PURPOSE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_ACCOUNT_PURPOSE_RECLASS ON DIM_ACCOUNT_PURPOSE.N_ACCOUNT_PURPOSE_SKEY = FSI_ACCOUNT_PURPOSE_RECLASS.N_ACCOUNT_PURPOSE_SKEY AND FSI_ACCOUNT_PURPOSE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_ACCOUNT_PURPOSE_RECLASS.N_RUN_SKEY = '870' LEFT OUTER JOIN DIM_BUSINESS_UNIT ON STG_LC_CONTRACTS.V_BUSINESS_UNIT_CODE = DIM_BUSINESS_UNIT.V_BUSINESS_UNIT_CODE LEFT OUTER JOIN DIM_CREDIT_LINE ON STG_LC_CONTRACTS.V_LINE_CODE = DIM_CREDIT_LINE.V_CREDIT_LINE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_CREDIT_LINE.D_RECORD_START_DATE AND DIM_CREDIT_LINE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_LC_CONTRACTS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON A_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = A_FSI_CAP